prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?prop (COUNT(*) as ?count) WHERE {
  {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-B5425D44-FF60-41FD-A19D-407767378426> ?prop ?value .
  } UNION {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-04EE0353-05EF-4429-9328-0E1B9554485C> ?prop ?value .
  }
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?intermediate ?intermediateName WHERE {
  # Sequence flow from Process provisioning to intermediate
  ?edge1 a bbo:SequenceFlow ;
         bbo:has_sourceRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-B5425D44-FF60-41FD-A19D-407767378426> ;
         bbo:has_targetRef ?intermediate .

  # Sequence flow from intermediate to Operations provisioning
  ?edge2 a bbo:SequenceFlow ;
         bbo:has_sourceRef ?intermediate ;
         bbo:has_targetRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-04EE0353-05EF-4429-9328-0E1B9554485C> .

  OPTIONAL { ?intermediate bbo:name ?intermediateName . }
}
